const { KnockMgmt } = require("@knocklabs/mgmt");

async function provisionWorkflow() {
  const runId = process.env.ZEALT_RUN_ID;
  const serviceToken = process.env.KNOCK_SERVICE_TOKEN;
  const workflowKey = `popover-demo-${runId}`;

  const knock = new KnockMgmt({ apiKey: serviceToken });

  console.log(`Provisioning workflow: ${workflowKey}`);

  try {
    // Upsert the workflow
    await knock.workflows.upsert(workflowKey, {
      name: `Popover Demo ${runId}`,
      steps: [
        {
          type: "channel",
          channel_key: "in-app",
          template: {
            body: "{{ data.body }}",
          },
        },
      ],
    });

    console.log(`Workflow ${workflowKey} upserted.`);

    // Activate the workflow in development
    // Note: The SDK might have a different way to activate, but usually it's part of upsert or a separate method.
    // Based on Knock documentation, upserting in development environment is usually enough if it's set to active.
    // However, the prompt says "Be active in the development environment".
    // Some versions of management API might not have a separate 'activate' method but 'active' flag in upsert.

    // Let's try to find an activate method or just use the upsert if it supports active flag.
    // Re-upsert with active: true if possible, or check if there is an activate method.

    if (knock.workflows.activate) {
        await knock.workflows.activate(workflowKey, {
            environment: "development"
        });
        console.log(`Workflow ${workflowKey} activated in development.`);
    } else {
        console.log("No activate method found on knock.workflows, hopefully upsert was enough or active by default.");
    }

  } catch (error) {
    console.error("Error provisioning workflow:", error);
    process.exit(1);
  }
}

